exercises.solution_code:
#include <iostream>

int main()
{
    int n {};
    std::cin >> n;

    if (n < 0)
    {
        std::cout << "Negative\n";
    }
    else if (n == 0)
    {
        std::cout << "Zero\n";
    }
    else
    {
        std::cout << "Positive\n";
    }

    return 0;
}

