exercises.solution_code:
#include <iostream>

int main()
{
    char initial {};
    int score {};

    std::cin >> initial >> score;

    char grade {};

    if (score >= 90)
    {
        grade = 'A';
    }
    else if (score >= 80)
    {
        grade = 'B';
    }
    else if (score >= 70)
    {
        grade = 'C';
    }
    else if (score >= 60)
    {
        grade = 'D';
    }
    else
    {
        grade = 'F';
    }

    std::cout << initial << ": " << grade << '\n';

    return 0;
}
